const item = $('New Feed Item').first().json;
const config = $('Configuration (EDIT ME)').first().json;

const title = String(item.title || '').trim();
if (!title) throw new Error('Feed item has no title');
const snippet = String(item.contentSnippet || '').trim().slice(0, 200);
const link = String(item.link || '').trim();

const caption = [title, snippet, link].filter(Boolean).join('\n\n');

// Prefer the article's own image (enclosure / media tags), fall back to the configured brand card.
const enclosure = item.enclosure && item.enclosure.url ? item.enclosure.url : null;
const picture = enclosure || item['media:content'] || item['ht:picture'] || null;

return [{ json: { caption, hashtags: '', picture } }];

const config = $('Configuration (EDIT ME)').first().json;
const draft = $('Build Caption').first().json;
const channels = $input.first().json.data || [];

const baseUrl = String(config.postStackUrl || '').replace(/\/+$/, '');
const wanted = String(config.channelIds || '').split(',').map((s) => s.trim()).filter(Boolean);
if (!wanted.length) throw new Error('channelIds in Configuration is empty');

const byId = new Map(channels.map((c) => [c.id, c]));
return wanted.map((id) => {
  const channel = byId.get(id);
  if (!channel) throw new Error(`Channel ${id} not found in PostStack - check channelIds`);
  return { json: {
    channelId: channel.id,
    platform: channel.platform,
    channelName: channel.display_name,
    caption: draft.caption,
    hashtags: draft.hashtags,
    imageUrl: draft.picture || config.imageUrl,
    createUrl: `${baseUrl}/api/v1/posts`,
  } };
});

const config = $('Configuration (EDIT ME)').first().json;
const baseUrl = String(config.postStackUrl || '').replace(/\/+$/, '');

return $input.all().map((item, i) => {
  const postId = item.json.data && item.json.data.id;
  if (!postId) throw new Error('Post creation did not return an id');
  const plan = $('Build Posts per Channel').all()[i].json;
  return { json: {
    publishUrl: `${baseUrl}/api/v1/posts/${postId}/publish`,
    channelId: plan.channelId,
    channelName: plan.channelName,
  } };
});
